          toast.error('❌ ' + errorMessage, {
            position: "top-center",
            autoClose: 5000,
          });

          setTimeout(() => {
            navigate('/payment');
          }, 3000);

        } else {
          console.log('⚠️ Không có response code từ VNPAY');
          setStatus("error");
          setTitle("Không thể xác nhận trạng thái");

          toast.warning('⚠️ Không thể xác nhận trạng thái thanh toán', {
            position: "top-center",
            autoClose: 5000,
          });

          setTimeout(() => {
            navigate('/payment');
          }, 3000);
        }

      } catch (error) {
        console.error('❌ Lỗi khi xử lý callback VNPAY:', error);
        setStatus("error");
        setTitle("Có lỗi xảy ra khi xác thực thanh toán");

        toast.error('❌ Lỗi khi xử lý thanh toán VNPAY', {
          position: "top-center",
          autoClose: 5000,
        });

        setTimeout(() => {
          navigate('/payment');
        }, 3000);
      } finally {
        setLoading(false);
      }
    };

    processPayment();
  }, []);

  if (loading) {
    return (
      <div style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#f5f5f5'
