            const newQuantity = Math.max(0, currentVoucher.soLuong - 1);

            const decreaseVoucherResponse = await fetch(config.getApiUrl(`api/voucher/update/${voucherId}`), {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
